.darma-loader-darma-custom-663__pl {color: var(--loader-color, #3b82f6);

  display: block;
  width: 9.375em;
  height: 9.375em;
}

.darma-loader-darma-custom-663__pl__arrows,
.darma-loader-darma-custom-663__pl__ring-rotate,
.darma-loader-darma-custom-663__pl__ring-stroke,
.darma-loader-darma-custom-663__pl__tick {
  animation-duration: var(--loader-speed, 2s);
  animation-timing-function: linear;
  animation-iteration-count: infinite;
}

.darma-loader-darma-custom-663__pl__arrows {
  animation-name: darma-loader-darma-custom-663-arrows42;
  transform: rotate(45deg);
  transform-origin: 16px 52px;
}

.darma-loader-darma-custom-663__pl__ring-rotate,
.darma-loader-darma-custom-663__pl__ring-stroke {
  transform-origin: 80px 80px;
}

.darma-loader-darma-custom-663__pl__ring-rotate {
  animation-name: darma-loader-darma-custom-663-ringRotate42;
}

.darma-loader-darma-custom-663__pl__ring-stroke {
  animation-name: darma-loader-darma-custom-663-ringStroke42;
  transform: rotate(-45deg);
}

.darma-loader-darma-custom-663__pl__tick {
  animation-name: darma-loader-darma-custom-663-tick42;
}

.darma-loader-darma-custom-663__pl__tick:nth-child(2) {
  animation-delay: -1.75s;
}

.darma-loader-darma-custom-663__pl__tick:nth-child(3) {
  animation-delay: -1.5s;
}

.darma-loader-darma-custom-663__pl__tick:nth-child(4) {
  animation-delay: -1.25s;
}

.darma-loader-darma-custom-663__pl__tick:nth-child(5) {
  animation-delay: -1s;
}

.darma-loader-darma-custom-663__pl__tick:nth-child(6) {
  animation-delay: -0.75s;
}

.darma-loader-darma-custom-663__pl__tick:nth-child(7) {
  animation-delay: -0.5s;
}

.darma-loader-darma-custom-663__pl__tick:nth-child(8) {
  animation-delay: -0.25s;
}

/* Animations */
@keyframes darma-loader-darma-custom-663-arrows42 {
  from {
    transform: rotate(45deg);
  }

  to {
    transform: rotate(405deg);
  }
}

@keyframes darma-loader-darma-custom-663-ringRotate42 {
  from {
    transform: rotate(0);
  }

  to {
    transform: rotate(720deg);
  }
}

@keyframes darma-loader-darma-custom-663-ringStroke42 {
  from,
	to {
    stroke-dashoffset: 452;
    transform: rotate(-45deg);
  }

  50% {
    stroke-dashoffset: 169.5;
    transform: rotate(-180deg);
  }
}

@keyframes darma-loader-darma-custom-663-tick42 {
  from,
	3%,
	47%,
	to {
    stroke-dashoffset: -12;
  }

  14%,
	36% {
    stroke-dashoffset: 0;
  }
}

.darma-loader-compass-spinner {
  position: relative;
